// ===== LOCK SCREEN — Asisten Petugas SE2026 =====
// PATCH v2: login berbasis Device ID + Nama Pengguna + Kode Aktivasi,
// dengan fitur LOGOUT supaya 1 kode aktivasi bisa dipindah ke perangkat
// lain (kode dilepas dulu dari device lama lewat action=logout, baru
// bisa dipakai login di device baru lewat action=aktivasi).

const URL_APPS_SCRIPT = 'https://script.google.com/macros/s/AKfycbzUMVTcWHvlpRiWK7runS6kg0tZrdmEzLJvKjCgenKGm3pZkc4hbfaASmP-bd5tb3j6sw/exec';
window.APPS_SCRIPT_URL = URL_APPS_SCRIPT;
const LOCK_STORAGE_KEY = 'se2026_kode_aktif_v1';
const DEVICE_ID_KEY = 'se2026_device_uuid_v1';
const NAMA_STORAGE_KEY = 'se2026_nama_pengguna_v1';

const lockScreen = document.getElementById('lockScreen');
const lockBox = document.getElementById('lockBox');
const inputKode = document.getElementById('kodeAkses');
const inputNama = document.getElementById('namaPengguna');
const lockMsg = document.getElementById('lockMsg');
const btnAktivasi = document.getElementById('btnAktivasi');
const deviceIdText = document.getElementById('deviceIdText');

// ===== Device ID (persisten per HP, dipakai sebagai identitas login) =====
function getOrCreateDeviceId() {
  let id = localStorage.getItem(DEVICE_ID_KEY);
  if (id) return id;
  id = (window.crypto && crypto.randomUUID)
    ? crypto.randomUUID()
    : ('dev-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2) + Math.random().toString(36).slice(2));
  id = id.toUpperCase();
  try { localStorage.setItem(DEVICE_ID_KEY, id); } catch (e) {}
  return id;
}

function renderDeviceIdUI() {
  if (deviceIdText) deviceIdText.textContent = getOrCreateDeviceId();
}

function copyDeviceId() {
  const id = getOrCreateDeviceId();
  const done = () => { if (typeof showToast === 'function') showToast('📋 Device ID tersalin'); };
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(id).then(done).catch(() => fallbackCopyDeviceId(id, done));
  } else {
    fallbackCopyDeviceId(id, done);
  }
}
function fallbackCopyDeviceId(text, done) {
  try {
    const ta = document.createElement('textarea');
    ta.value = text;
    ta.style.position = 'fixed';
    ta.style.opacity = '0';
    document.body.appendChild(ta);
    ta.select();
    document.execCommand('copy');
    document.body.removeChild(ta);
    done();
  } catch (e) {}
}

function showLockMsg(text, type) {
  if (!lockMsg) return;
  lockMsg.textContent = text;
  lockMsg.className = 'lock-msg show ' + type;
}
function hideLockMsg() {
  if (!lockMsg) return;
  lockMsg.className = 'lock-msg';
}
function setLockLoading(loading) {
  if (!btnAktivasi) return;
  btnAktivasi.disabled = loading;
  btnAktivasi.textContent = loading ? 'Memproses…' : 'Masuk';
}

function getStoredKode() { return localStorage.getItem(LOCK_STORAGE_KEY); }
function getStoredNama() { return localStorage.getItem(NAMA_STORAGE_KEY); }

// ===== Verifikasi ulang (background, tiap 10 detik + tiap app dibuka) =====
async function verifikasiKodeBackground(kode) {
  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), 5000);
  try {
    const device = encodeURIComponent(getOrCreateDeviceId());
    const url = URL_APPS_SCRIPT + '?action=cek&kode=' + encodeURIComponent(kode) + '&device=' + device;
    const res = await fetch(url, { signal: controller.signal });
    const data = await res.json();
    if (!data.success) return;
    if (data.status === 'aktif') return; // masih sah, tidak perlu apa-apa
    // status: 'belum' | 'expired' | 'aktif_beda_device' -> paksa logout lokal
    window.__appUnlocked = false;
    localStorage.removeItem(LOCK_STORAGE_KEY);
    localStorage.removeItem(NAMA_STORAGE_KEY);
    lockScreen.classList.remove('hidden');
    renderDeviceIdUI();
    if (data.status === 'aktif_beda_device') {
      showLockMsg('⚠️ Kode ini sedang dipakai di perangkat lain. Logout dulu dari perangkat itu, atau aktivasi kode baru.', 'error');
    } else if (data.status === 'expired') {
      showLockMsg('⚠️ Kode aktivasi sudah kadaluarsa.', 'error');
    } else {
      showLockMsg('⚠️ Sesi login berakhir. Silakan masuk kembali.', 'error');
    }
  } catch (e) {
    // offline / timeout -> biarkan tetap terbuka (mode offline)
  } finally {
    clearTimeout(t);
  }
}

// ===== Masuk (aktivasi kode di device ini) =====
async function aktivasiKode() {
  const kode = (inputKode.value || '').trim().toUpperCase();
  const nama = (inputNama && inputNama.value || '').trim();

  if (!nama) return showLockMsg('⚠️ Nama Pengguna wajib diisi.', 'error');
  if (!kode) return showLockMsg('⚠️ Kode Aktivasi wajib diisi.', 'error');
  if (!navigator.onLine) return showLockMsg('⚠️ Butuh koneksi internet untuk login pertama kali.', 'error');

  setLockLoading(true);
  hideLockMsg();
  try {
    const device = getOrCreateDeviceId();
    const url = URL_APPS_SCRIPT + '?action=aktivasi&kode=' + encodeURIComponent(kode)
      + '&device=' + encodeURIComponent(device) + '&nama=' + encodeURIComponent(nama);
    const res = await fetch(url);
    const data = await res.json();
    setLockLoading(false);

    if (data.success) {
      localStorage.setItem(LOCK_STORAGE_KEY, kode);
      localStorage.setItem(NAMA_STORAGE_KEY, nama);
      window.__appUnlocked = true;
      showLockMsg('✅ ' + (data.message || 'Login berhasil.'), 'info');
      if (typeof window.tarikDataSinkron === 'function') window.tarikDataSinkron(kode, device);
      setTimeout(() => { lockScreen.classList.add('hidden'); }, 500);
    } else {
      showLockMsg('❌ ' + (data.message || 'Kode aktivasi tidak valid.'), 'error');
      lockBox.style.animation = 'shake .4s';
      setTimeout(() => { lockBox.style.animation = ''; }, 400);
    }
  } catch (e) {
    setLockLoading(false);
    showLockMsg('❌ Gagal terhubung ke server. Cek koneksi internet.', 'error');
  }
}

// ===== Logout (lepas kode dari device ini supaya bisa dipakai device lain) =====
async function logoutAkun() {
  const kode = getStoredKode();
  if (!kode) return;
  if (!confirm('Logout dari aplikasi ini?\n\nKode aktivasi akan dilepas dari perangkat ini dan bisa dipakai login di perangkat lain. Data yang sudah tersimpan di HP ini TIDAK terhapus.')) return;
  if (!navigator.onLine) return void (typeof showToast === 'function' && showToast('⚠️ Butuh koneksi internet untuk logout'));

  try {
    const device = encodeURIComponent(getOrCreateDeviceId());
    const url = URL_APPS_SCRIPT + '?action=logout&kode=' + encodeURIComponent(kode) + '&device=' + device;
    const res = await fetch(url);
    const data = await res.json();
    if (data.success) {
      localStorage.removeItem(LOCK_STORAGE_KEY);
      localStorage.removeItem(NAMA_STORAGE_KEY);
      window.__appUnlocked = false;
      if (typeof showToast === 'function') showToast('✅ Logout berhasil');
      location.reload();
    } else {
      if (typeof showToast === 'function') showToast('❌ ' + (data.message || 'Gagal logout'));
    }
  } catch (e) {
    if (typeof showToast === 'function') showToast('❌ Gagal terhubung ke server');
  }
}

// ===== Init =====
window.__appUnlocked = false;
(function () {
  renderDeviceIdUI();
  const kodeTersimpan = getStoredKode();
  const namaTersimpan = getStoredNama();
  if (kodeTersimpan) {
    window.__appUnlocked = true;
    lockScreen.classList.add('hidden');
    if (navigator.onLine) {
      verifikasiKodeBackground(kodeTersimpan);
      if (typeof window.tarikDataSinkron === 'function') window.tarikDataSinkron(kodeTersimpan, getOrCreateDeviceId());
    }
  }
  if (namaTersimpan && inputNama) inputNama.value = namaTersimpan;
})();

setInterval(function () {
  if (!window.__appUnlocked) return;
  const kode = getStoredKode();
  if (!kode) { window.__appUnlocked = false; lockScreen.classList.remove('hidden'); return; }
  if (navigator.onLine) verifikasiKodeBackground(kode);
}, 10000);

if (inputKode) {
  inputKode.addEventListener('keydown', (e) => { if (e.key === 'Enter') aktivasiKode(); });
}
if (inputNama) {
  inputNama.addEventListener('keydown', (e) => { if (e.key === 'Enter') aktivasiKode(); });
}

window.aktivasiKode = aktivasiKode;
window.logoutAkun = logoutAkun;
window.copyDeviceId = copyDeviceId;
